33 | @Command(name = "e2m", description = "Eclipse project to Maven project converter", version = "1.0", mixinStandardHelpOptions = true)
34 | public class Main implements Callable<Integer> {
35 | 
36 |     @Option(names = {"-g", "--groupId"}, required = false, description = "Maven groupId of the output project")
37 |     private String groupId;
38 | 
39 |     @Option(names = {"-a", "--artifactId"}, required = false, description = "Maven artifactId of the output project")
40 |     private String artifactId;
41 | 
42 |     @Option(names = {"-v", "--artifactVersion"}, required = false, description = "Maven version of the output project (default: 1.0-SNAPSHOT)")
43 |     private String artifactVersion;
44 |     private static final String DEFAULT_ARTIFACT_VERSION = "1.0-SNAPSHOT";
45 | 
46 |     @Option(names = {"--javaTargetVersion"}, required = false, converter = JavaVersionConverter.class,
47 |             description = "Override maven.compiler.target in the generated pom.xml (default: taken from the Eclipse project settings)")
48 |     private JavaVersion javaTargetVersion;
49 | 
50 |     @Option(names = {"--debug"}, description = "Output debug information as e2m_debug_<datetime>.zip in the output directory")
51 |     private boolean debug;
52 | 
53 |     @Parameters(index = "0", paramLabel = "<inputDir>", description = "Eclipse project directory to convert")
54 |     private File inputDir;
55 | 
56 |     @Parameters(index = "1", paramLabel = "<outputDir>", description = "Output directory for the Maven project")
57 |     private File outputDir;
58 | 
59 |     public static void main(String[] args) {
60 |         System.exit(new CommandLine(new Main()).execute(args));
61 |     }
62 | 
63 |     @Override
64 |     public Integer call() {
65 |         Path inputPath = inputDir.toPath();
66 | 
67 |         // 1. 引数の確認
68 |         if (!inputDir.isDirectory()) {
69 |             System.err.println("[ERROR] 入力ディレクトリが見つかりません: " + inputDir);
70 |             return 1;
71 |         }
72 |         if (!inputPath.resolve(".project").toFile().exists()) {
73 |             System.err.println("[ERROR] Eclipseプロジェクトではありません (.project ファイルが見つかりません): " + inputDir);
74 |             return 1;
75 |         }
76 |         if (outputDir.exists() && !outputDir.isDirectory()) {
77 |             System.err.println("[ERROR] 出力パスはディレクトリである必要があります: " + outputDir);
78 |             return 1;
79 |         }
80 |         if (javaTargetVersion != null && javaTargetVersion.isUnknown()) {
81 |             System.err.println("[ERROR] --javaTargetVersionが不正です: " + javaTargetVersion);
82 |             return 1;
83 |         }
84 | 
85 |         try {
86 |             // 2. Eclipseプロジェクト情報をパース
87 |             System.out.println("\n[1/5] Eclipseプロジェクトを解析中...");
88 |             EclipseProject eclipseProject = EclipseProjectParser.parse(inputPath);
89 |             System.out.println("  プロジェクト名: " + eclipseProject.projectName());
90 |             System.out.println("  種別: " + (eclipseProject.webProject() ? "Webプロジェクト (WTP)" : "Javaプロジェクト"));
91 |             System.out.println("  Javaソースバージョン: " + eclipseProject.javaSourceVersion());
92 |             System.out.println("  Javaターゲットバージョン: " + eclipseProject.javaTargetVersion());
93 |             if (eclipseProject.webProject()) {
94 |                 System.out.println("  Web仕様バージョン: " + eclipseProject.webVersion());
95 |             }
96 |             System.out.println("  ソースフォルダ: " + eclipseProject.sourceFolders());
97 |             if (eclipseProject.webProject()) {
98 |                 System.out.println("  Webコンテンツフォルダ: " + eclipseProject.webContentRoot());
99 |             }
100 |             System.out.println("  JARファイル数: " + eclipseProject.jarPaths().size());
101 | 
102 |             if (eclipseProject.javaSourceVersion().isUnknown()) {
103 |                 System.err.println("[ERROR] Javaソースバージョンを認識できませんでした: "
104 |                         + eclipseProject.javaSourceVersion());
105 |                 return 1;
106 |             }
107 | 
108 |             System.out.println("\n[2/5] 移行先のMavenプロジェクトを決定中...");
109 |             String defaultArtifactId = convertToArtifactId(eclipseProject.projectName());
110 |             if (groupId == null || groupId.isBlank()) {
111 |                 // オプション未指定の場合は対話的に入力を受け付ける
112 |                 try (BufferedReader reader = new BufferedReader(new InputStreamReader(System.in))) {
113 |                     groupId = promptIfAbsent(reader, "groupId", groupId, null);
114 |                     artifactId = promptIfAbsent(reader, "artifactId", artifactId, defaultArtifactId);
115 |                     artifactVersion = promptIfAbsent(reader, "artifactVersion", artifactVersion, DEFAULT_ARTIFACT_VERSION);
116 |                 }
117 |             } else {
118 |                 // 少なくとも--groupIdが指定されていれば，あとは空ならデフォルトを使用する
119 |                 if (artifactId == null || artifactId.isBlank()) {
120 |                     artifactId = defaultArtifactId;
121 |                 }
122 |                 if (artifactVersion == null || artifactId.isBlank()) {
123 |                     artifactVersion = DEFAULT_ARTIFACT_VERSION;
124 |                 }
125 |                 System.out.println("groupId: " + groupId);
126 |                 System.out.println("artifactId: " + artifactId);
127 |                 System.out.println("version: " + artifactVersion);
128 |             }
129 | 
130 |             // 出力先は outputDir/artifactId
131 |             Path outputPath = outputDir.toPath().resolve(artifactId);
132 |             if (outputPath.toFile().exists()) {
133 |                 System.err.println("[ERROR] 出力先ディレクトリがすでに存在しています: " + outputPath);
134 |                 return 1;
135 |             }
136 | 
137 |             System.out.println("\n=== e2m: Eclipse → Maven 変換開始 ===");
138 |             System.out.println("  入力: " + inputPath.toAbsolutePath());
139 |             System.out.println("  出力: " + outputPath.toAbsolutePath());
140 | 
141 |             // 3.(続き) JAR依存関係を解決
142 |             System.out.println("\n[3/5] JAR依存関係を解決中...");
143 |             List<MavenDependency> dependencies = DependencyResolver.resolve(eclipseProject.jarPaths(), inputPath);
144 |             long found = dependencies.stream().filter(d -> !"system".equals(d.scope())).count();
145 |             long system = dependencies.stream().filter(d -> "system".equals(d.scope())).count();
146 |             System.out.println("  Maven Central で見つかった依存: " + found + " 件");
147 |             System.out.println("  system スコープの依存: " + system + " 件");
148 | 
149 |             // 4. pom.xml を生成
150 |             System.out.println("\n[4/5] pom.xml を生成中...");
151 |             // --javaTargetVersion が指定された場合はソースバージョンと比較してバリデーション
152 |             JavaVersion sourceVer = eclipseProject.javaSourceVersion();
153 |             if (javaTargetVersion != null) {
154 |                 if (!sourceVer.isUnknown() && javaTargetVersion.compareTo(sourceVer) < 0) {
155 |                     System.err.println("[ERROR] --javaTargetVersion (" + javaTargetVersion
156 |                             + ") はJavaソースバージョン (" + eclipseProject.javaSourceVersion()
157 |                             + ") より低いバージョンを指定することはできません。");
158 |                     return 1;
159 |                 }
160 |             }
161 |             PomGenerator.generate(eclipseProject, dependencies, groupId, artifactId, artifactVersion,
162 |                     javaTargetVersion, outputPath);
163 | 
164 |             // 5. ソース・Webコンテンツをコピー
165 |             System.out.println("\n[5/5] ソースファイルをコピー中...");
166 |             ProjectCopier.copy(eclipseProject, dependencies, inputPath, outputPath);
167 | 
168 |             System.out.println("\n=== 変換完了 ===");
169 |             System.out.println("出力先: " + outputPath.toAbsolutePath());
170 | 
171 |             // --debug オプション: デバッグ ZIP を生成
172 |             if (debug) {
173 |                 DebugArchiver.archive(inputPath, outputDir.toPath(), outputPath);
174 |             }
175 | 
176 |             return 0;
177 | 
178 |         } catch (Exception e) {
179 |             System.err.println("[ERROR] 変換中にエラーが発生しました: " + e.getMessage());
180 |             e.printStackTrace(System.err);
181 |             return 2;
182 |         }
183 |     }
184 | 
185 |     /**
186 |      * 引数が null または空の場合にプロンプトを表示して入力を受け付ける。
187 |      * デフォルト値がある場合は "[default]" 形式で表示し、空入力でデフォルト値を採用する。
188 |      *
189 |      * @param reader       入力ストリーム
190 |      * @param name         項目名（表示用）
191 |      * @param value        コマンドライン引数の値（null または空の場合にプロンプト表示）
192 |      * @param defaultValue デフォルト値（null の場合はデフォルトなし）
193 |      * @return 確定した値
194 |      */
195 |     private static String promptIfAbsent(BufferedReader reader, String name,
196 |             String value, String defaultValue) throws Exception {
197 |         if (value != null && !value.isBlank()) {
198 |             return value;
199 |         }
200 |         while (true) {
201 |             if (defaultValue != null) {
202 |                 System.out.print(name + " [" + defaultValue + "]: ");
203 |             } else {
204 |                 System.out.print(name + ": ");
205 |             }
206 |             System.out.flush();
207 |             String line = reader.readLine();
208 |             if (line == null) {
209 |                 // EOF（パイプ等）の場合はデフォルト値を使用
210 |                 return defaultValue != null ? defaultValue : "";
211 |             }
212 |             String trimmed = line.trim();
213 |             if (trimmed.isEmpty()) {
214 |                 if (defaultValue != null) {
215 |                     return defaultValue;
216 |                 }
217 |                 System.err.println("  値を入力してください。");
218 |                 continue;
219 |             }
220 |             return trimmed;
221 |         }
222 |     }
