224 |     // artifactIdとして許可する文字（半角英数字、ハイフン、アンダースコア）以外にマッチする正規表現
225 |     private static final Pattern INVALID_CHARS = Pattern.compile("[^a-z0-9\\-_]");
226 | 
227 |     // キャメルケースの境界（大文字の前）にマッチする正規表現
228 |     private static final Pattern CAMEL_CASE_BOUNDARY = Pattern.compile("(?<=[a-z0-9])(?=[A-Z])");
229 | 
230 |     /**
231 |      * プロジェクト名からMavenのartifactIdとして利用可能な文字列を生成します。
232 |      *
233 |      * @param projectName プロジェクト名
234 |      * @return artifactId用文字列
235 |      */
236 |     public static String convertToArtifactId(String projectName) {
237 |         if (projectName == null || projectName.isBlank()) {
238 |             return "default-artifact";
239 |         }
240 | 
241 |         // 1. パッケージ名が含まれている場合（完全限定名）、最後のクラス名部分だけを抽出
242 |         String simpleName = projectName.substring(projectName.lastIndexOf('.') + 1);
243 | 
244 |         // 2. キャメルケース（OrderManager -> Order-Manager）をハイフン区切りに変換
245 |         String kebabCase = CAMEL_CASE_BOUNDARY.matcher(simpleName).replaceAll("-");
246 | 
247 |         // 3. すべて小文字に変換
248 |         String lowerCase = kebabCase.toLowerCase();
249 | 
250 |         // 4. artifactIdとして使えない文字（日本語や特殊記号など）を完全に除去
251 |         String sanitized = INVALID_CHARS.matcher(lowerCase).replaceAll("");
252 | 
253 |         // 5. 連続したハイフンやアンダースコアを綺麗に整理
254 |         sanitized = sanitized.replaceAll("[-_]{2,}", "-");
255 | 
256 |         // 6. 先頭や末尾にあるハイフン・アンダースコアを除去
257 |         sanitized = sanitized.replaceAll("^[-_]+|[-_]+$", "");
258 | 
259 |         // すべての文字が削られて空になった場合のフォールバック
260 |         return sanitized.isBlank() ? "converted-artifact" : sanitized;
261 |     }
262 | 
263 |     /**
264 |      * picocli 用の {@link JavaVersion} 型変換クラス。
265 |      * 変換に失敗した場合は {@link JavaVersion#UNKNOWN_VERSION} を返す。
266 |      */
267 |     static class JavaVersionConverter implements ITypeConverter<JavaVersion> {
268 |         @Override
269 |         public JavaVersion convert(String value) {
270 |             return JavaVersion.of(value);
271 |         }
272 |     }
273 | }
